import{_ as a,o as t,c as r,a2 as n}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"SageAgent — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/sage-agent/benchmarks.md","filePath":"research/agents/sage-agent/benchmarks.md"}'),i={name:"research/agents/sage-agent/benchmarks.md"};function o(s,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="sageagent-—-benchmarks" tabindex="-1">SageAgent — Benchmarks <a class="header-anchor" href="#sageagent-—-benchmarks" aria-label="Permalink to &quot;SageAgent — Benchmarks&quot;">​</a></h1><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><p>SageAgent&#39;s primary public benchmark result is from Terminal-Bench 2.0, a benchmark for evaluating coding agent performance on terminal-based tasks.</p><h3 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Benchmark</td><td>Terminal-Bench 2.0</td></tr><tr><td>Agent</td><td>SageAgent</td></tr><tr><td>Model</td><td>GPT-5.3-Codex</td></tr><tr><td>Score</td><td><strong>78.4% ±2.2</strong></td></tr><tr><td>Rank</td><td><strong>#5</strong></td></tr><tr><td>Date</td><td>2026-03-13</td></tr></tbody></table><h3 id="leaderboard-context" tabindex="-1">Leaderboard Context <a class="header-anchor" href="#leaderboard-context" aria-label="Permalink to &quot;Leaderboard Context&quot;">​</a></h3><p>SageAgent&#39;s score of 78.4% places it at rank #5 on the Terminal-Bench 2.0 leaderboard. This score ties with ForgeCode using Gemini 3.1 Pro, which also achieved 78.4%.</p><p>The ±2.2 confidence interval suggests the benchmark was run multiple times with variance across runs, which is standard practice for stochastic agent evaluations.</p><h3 id="interpretation" tabindex="-1">Interpretation <a class="header-anchor" href="#interpretation" aria-label="Permalink to &quot;Interpretation&quot;">​</a></h3><ul><li><strong>Competitive showing</strong>: Rank #5 on a major coding benchmark is a solid result for a multi-agent framework, demonstrating that the pipeline architecture can translate to effective task completion.</li><li><strong>Model dependency</strong>: The result is achieved with GPT-5.3-Codex specifically. Performance with other models is not publicly documented, though the roadmap mentions expanding tested model support.</li><li><strong>Multi-agent overhead</strong>: The pipeline architecture (5 agents, feedback loop) adds latency compared to single-agent approaches. The benchmark score suggests this overhead is offset by improved task decomposition and iterative refinement.</li></ul><h2 id="other-benchmarks" tabindex="-1">Other Benchmarks <a class="header-anchor" href="#other-benchmarks" aria-label="Permalink to &quot;Other Benchmarks&quot;">​</a></h2><p>No other public benchmark results were found for SageAgent. The roadmap items suggest the project is still in relatively early stages, with benchmark coverage likely to expand as the framework matures.</p><h2 id="limitations-of-this-analysis" tabindex="-1">Limitations of This Analysis <a class="header-anchor" href="#limitations-of-this-analysis" aria-label="Permalink to &quot;Limitations of This Analysis&quot;">​</a></h2><ul><li>Only one benchmark data point is available</li><li>Historical performance trends are not documented</li><li>Per-category breakdown within Terminal-Bench 2.0 is not available</li><li>Comparison across different model backends is not available</li></ul><hr><p><em>Tier 3 analysis — benchmark data from Terminal-Bench 2.0 leaderboard.</em></p>',16)])])}const p=a(i,[["render",o]]);export{g as __pageData,p as default};
